// MARK: - Promo Link Parser

class PromoLinkParser {
    
    static let validHost = "myapp.com"
    static let validPath = "/promo"
    
    struct ParsedPromo {
        let code: String
        let discountPercentage: Int
        let source: PromoSource?
        let campaignId: String?
    }
    
    enum PromoSource: String {
        case email
        case sms
        case social
        case push
        case unknown
    }
    
    static func parse(url: URL) -> Result<ParsedPromo, PromoError> {
        guard let components = URLComponents(url: url, resolvingAgainstBaseURL: true) else {
            return .failure(.invalidURL)
        }
        
        guard components.host == validHost, components.path == validPath else {
            return .failure(.invalidURL)
        }
        
        let queryItems = components.queryItems ?? []
        
        guard let code = queryItems.first(where: { $0.name == "code" })?.value,
              !code.isEmpty else {
            return .failure(.missingPromoCode)
        }
        
        guard let discountString = queryItems.first(where: { $0.name == "discount" })?.value else {
            return .failure(.missingDiscount)
        }
        
        guard let discount = Int(discountString), discount > 0, discount <= 100 else {
            return .failure(.invalidDiscount)
        }
        
        let sourceString = queryItems.first(where: { $0.name == "source" })?.value
        let source = sourceString.flatMap { PromoSource(rawValue: $0) } ?? .unknown
        
        let campaignId = queryItems.first(where: { $0.name == "campaign" })?.value
        
        let parsedPromo = ParsedPromo(
            code: code.uppercased(),
            discountPercentage: discount,
            source: source,
            campaignId: campaignId
        )
        
        return .success(parsedPromo)
    }
}

// MARK: - User Account Manager

class UserAccountManager {
    
    static let shared = UserAccountManager()
    
    private let defaults = UserDefaults.standard
    
    private enum Keys {
        static let isLoggedIn = "user_is_logged_in"
        static let userId = "user_id"
        static let appliedPromoCode = "applied_promo_code"
        static let appliedDiscount = "applied_discount"
        static let usedPromoCodes = "used_promo_codes"
        static let promoApplicationDate = "promo_application_date"
    }
    
    var isLoggedIn: Bool {
        return defaults.bool(forKey: Keys.isLoggedIn)
    }
    
    var userId: String? {
        return defaults.string(forKey: Keys.userId)
    }
    
    var currentPromoCode: String? {
        return defaults.string(forKey: Keys.appliedPromoCode)
    }
    
    var currentDiscount: Int {
        return defaults.integer(forKey: Keys.appliedDiscount)
    }
    
    var usedPromoCodes: [String] {
        return defaults.stringArray(forKey: Keys.usedPromoCodes) ?? []
    }
    
    private init() {}
    
    func login(userId: String) {
        defaults.set(true, forKey: Keys.isLoggedIn)
        defaults.set(userId, forKey: Keys.userId)
    }
    
    func logout() {
        defaults.set(false, forKey: Keys.isLoggedIn)
        defaults.removeObject(forKey: Keys.userId)
        defaults.removeObject(forKey: Keys.appliedPromoCode)
        defaults.removeObject(forKey: Keys.appliedDiscount)
    }
    
    func hasUsedPromoCode(_ code: String) -> Bool {
        return usedPromoCodes.contains(code.uppercased())
    }
    
    func applyPromoCode(_ code: String, discount: Int) -> Result<PromoApplicationResult, PromoError> {
        guard isLoggedIn else {
            return .failure(.userNotLoggedIn)
        }
        
        let normalizedCode = code.uppercased()
        
        if hasUsedPromoCode(normalizedCode) {
            return .failure(.alreadyUsed)
        }
        
        if currentPromoCode != nil {
            return .failure(.alreadyApplied)
        }
        
        defaults.set(normalizedCode, forKey: Keys.appliedPromoCode)
        defaults.set(discount, forKey: Keys.appliedDiscount)
        defaults.set(Date(), forKey: Keys.promoApplicationDate)
        
        var used = usedPromoCodes
        used.append(normalizedCode)
        defaults.set(used, forKey: Keys.usedPromoCodes)
        
        let result = PromoApplicationResult(
            success: true,
            message: "Promo code \(normalizedCode) applied! You get \(discount)% off.",
            appliedDiscount: discount,
            promoCode: normalizedCode
        )
        
        return .success(result)
    }
    
    func removeCurrentPromo() {
        defaults.removeObject(forKey: Keys.appliedPromoCode)
        defaults.removeObject(forKey: Keys.appliedDiscount)
        defaults.removeObject(forKey: Keys.promoApplicationDate)
    }
}

