// MARK: - Promo Coordinator

class PromoCoordinator {
    
    static let shared = PromoCoordinator()
    
    private var pendingPromo: PromoLinkParser.ParsedPromo?
    
    private init() {}
    
    func handleUniversalLink(_ url: URL, from viewController: UIViewController? = nil) {
        let parseResult = PromoLinkParser.parse(url: url)
        
        switch parseResult {
        case .success(let parsedPromo):
            processPromo(parsedPromo, from: viewController)
            
        case .failure(let error):
            showError(error, from: viewController)
        }
    }
    
    func processPromo(_ promo: PromoLinkParser.ParsedPromo, from viewController: UIViewController? = nil) {
        guard UserAccountManager.shared.isLoggedIn else {
            pendingPromo = promo
            showLoginPrompt(from: viewController)
            return
        }
        
        // Track the promo link click
        PromoService.shared.trackPromoUsage(
            code: promo.code,
            source: promo.source,
            campaignId: promo.campaignId,
            userId: UserAccountManager.shared.userId
        )
        
        // Check if already used locally before hitting the server
        if UserAccountManager.shared.hasUsedPromoCode(promo.code) {
            showError(.alreadyUsed, from: viewController)
            return
        }
        
        // Validate with server
        showLoadingIndicator(from: viewController)
        
        PromoService.shared.validatePromoCode(promo.code, discount: promo.discountPercentage) { [weak self] result in
            DispatchQueue.main.async {
                self?.hideLoadingIndicator(from: viewController)
                
                switch result {
                case .success(let validatedPromo):
                    self?.applyValidatedPromo(validatedPromo, from: viewController)
                    
                case .failure(let error):
                    self?.showError(error, from: viewController)
                }
            }
        }
    }
    
    func processPendingPromoIfNeeded(from viewController: UIViewController? = nil) {
        guard let pending = pendingPromo else { return }
        pendingPromo = nil
        processPromo(pending, from: viewController)
    }
    
    private func applyValidatedPromo(_ promoCode: PromoCode, from viewController: UIViewController?) {
        let result = UserAccountManager.shared.applyPromoCode(
            promoCode.code,
            discount: promoCode.discountPercentage
        )
        
        switch result {
        case .success(let applicationResult):
            showSuccess(applicationResult, from: viewController)
            
            NotificationCenter.default.post(
                name: .promoCodeApplied,
                object: nil,
                userInfo: [
                    "code": promoCode.code,
                    "discount": promoCode.discountPercentage
                ]
            )
            
        case .failure(let error):
            showError(error, from: viewController)
        }
    }
    
    // MARK: - UI Helpers
    
    private func showSuccess(_ result: PromoApplicationResult, from viewController: UIViewController?) {
        let presenter = viewController ?? topViewController()
        
        let alert = UIAlertController(
            title: "🎉 Promo Applied!",
            message: result.message,
            preferredStyle: .alert
        )
        alert.addAction(UIAlertAction(title: "Great!", style: .default))
        presenter?.present(alert, animated: true)
    }
    
    private func showError(_ error: PromoError, from viewController: UIViewController?) {
        let presenter = viewController ?? topViewController()
        
        let alert = UIAlertController(
            title: "Promo Code Error",
            message: error.localizedDescription,
            preferredStyle: .alert
        )
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        presenter?.present(alert, animated: true)
    }
    
    private func showLoginPrompt(from viewController: UIViewController?) {
        let presenter = viewController ?? topViewController()
        
        let alert = UIAlertController(
            title: "Login Required",
            message: "Please log in to apply your promo code. The discount will be applied automatically after login.",
            preferredStyle: .alert
        )
        alert.addAction(UIAlertAction(title: "Log In", style: .default) { _ in
            // Navigate to login screen
            NotificationCenter.default.post(name: .showLoginScreen, object: nil)
        })
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel) { [weak self] _ in
            self?.pendingPromo = nil
        })
        presenter?.present(alert, animated: true)
    }
    
    private func showLoadingIndicator(from viewController: UIViewController?) {
        // In production, show a proper loading HUD
        print("[UI] Showing loading indicator...")
    }
    
    private func hideLoadingIndicator(from viewController: UIViewController?) {
        print("[UI] Hiding loading indicator...")
    }
    
    private func topViewController() -> UIViewController? {
        guard let windowScene = UIApplication.shared.connectedScenes.first as? UIWindowScene,
              let window = windowScene.windows.first(where: { $0.isKeyWindow }) else {
            return nil
        }
        
        var topController = window.rootViewController
        while let presented = topController?.presentedViewController {
            topController = presented
        }
        return topController
    }
}

